{"type":"tool_use","id":"call_3edca87ebcca4b0aafbc11f3","name":"Write","input":{"file_path":"/Users/xin/auto-skills/.claude/worktrees/worker-task-5/src/indexers/go-indexer.ts","content":"import { execFile } from "child_process";
import { readFile, access, constants } from "fs/promises";
import { promisify } from "util";
import * as path from "path";

const execFileAsync = promisify(execFile);

export interface IndexResult {
  files: string[];
  symbolCount: number;
  errors: string[];
}

export interface ScipSymbol {
  scheme: string;
  entity: string;
  descriptor: string;
}

export interface ParsedScipDocument {
  relativePath: string;
  language: string;
  occurrences: {
    range: [number, number];
    symbol: string;
    symbolRoles: number;
    overrideDepth: number;
  }[];
}

export function parseScipSymbols(doc: ParsedScipDocument): ScipSymbol[] {
  const seen = new Set<string>();
  const symbols: ScipSymbol[] = [];
  for (const occ of doc.occurrences) {
    if (seen.has(occ.symbol)) continue;
    seen.add(occ.symbol);
    const parts = occ.symbol.split(" ");
    symbols.push({
      scheme: parts[0] || "",
      entity: parts[1] || "",
      descriptor: parts.slice(2).join(" "),
    });
  }
  return symbols;
}

interface ScipIndex {
  metadata: {
    toolInfo: { name: string; version: string };
    projectRoot: string;
    textDocumentEncoding: string;
  };
  documents: {
    [relativePath: string]: ParsedScipDocument & { occurrences: unknown[] };
  };
  externalSymbols: unknown[];
}

function parseScipOutput(data: ScipIndex): IndexResult {
  const files: string[] = [];
  let symbolCount = 0;
  const errors: string[] = [];

  if (!data.documents) {
    errors.push("SCIP output contains no documents");
    return { files, symbolCount, errors };
  }

  for (const [relPath, doc] of Object.entries(data.documents)) {
    if (!relPath || !doc) {
      errors.push(`Skipping invalid document entry`);
      continue;
    }
    files.push(relPath);
    const symbols = parseScipSymbols(doc as ParsedScipDocument);
    symbolCount += symbols.length;
  }

  return { files, symbolCount, errors };
}

async function findScipGo(): Promise<string> {
  const candidates = ["scip-go"];
  for (const cmd of candidates) {
    try {
      await access(cmd, constants.X_OK);
      return cmd;
    } catch {
      continue;
    }
  }
  throw new Error(
    "scip-go not found in PATH. Install it from https://github.com/sourcegraph/scip-go"
  );
}

async function validateTargetDir(targetDir: string): Promise<void> {
  try {
    await access(targetDir, constants.R_OK | constants.X_OK);
  } catch {
    throw new Error(
      `Target directory does not exist or is not readable: ${targetDir}`
    );
  }
}

export async function indexGoProject(
  targetDir: string,
  options?: {
    scipGoPath?: string;
    outputDir?: string;
    timeoutMs?: number;
  }
): Promise<IndexResult> {
  const absTarget = path.resolve(targetDir);
  const errors: string[] = [];

  await validateTargetDir(absTarget);

  const scipGoBin = options?.scipGoPath || (await findScipGo());
  const outputDir = options?.outputDir || absTarget;
  const timeoutMs = options?.timeoutMs || 120_000;

  const args = ["index"];

  try {
    await execFileAsync(scipGoBin, args, {
      cwd: absTarget,
      timeout: timeoutMs,
      maxBuffer: 10 * 1024 * 1024,
    });
  } catch (err: unknown) {
    const msg = err instanceof Error ? err.message : String(err);
    throw new Error(`scip-go execution failed: ${msg}`);
  }

  const scipPath = path.join(outputDir, "index.scip");
  let scipData: ScipIndex;

  try {
    const raw = await readFile(scipPath, "utf-8");
    scipData = JSON.parse(raw) as ScipIndex;
  } catch (err: unknown) {
    const msg = err instanceof Error ? err.message : String(err);
    if ((err as NodeJS.ErrnoException).code === "ENOENT") {
      errors.push(
        `scip-go completed but no index.scip found at ${scipPath}`
      );
      return { files: [], symbolCount: 0, errors };
    }
    errors.push(`Failed to parse SCIP output: ${msg}`);
    return { files: [], symbolCount: 0, errors };
  }

  const result = parseScipOutput(scipData);
  result.errors.push(...errors);
  return result;
}
